```javascript
// ThemeContext.jsx
import { createContext, useState, useContext } from 'react';

const ThemeContext = createContext('light');

export function ThemeProvider({ children }) {
  const [theme, setTheme] = useState('light');
  const toggleTheme = () => {
    setTheme(prev => prev === 'light' ? 'dark' : 'light');
  };
  return (
    <ThemeContext.Provider value={{ theme, toggleTheme }}>
      {children}
    </ThemeContext.Provider>
  );
}

export function useTheme() {
  return useContext(ThemeContext);
}

// ThemedButton.jsx
import { useTheme } from './ThemeContext';

export function ThemedButton() {
  const { theme, toggleTheme } = useTheme();
  return (
    <button onClick={toggleTheme}>
      Activer mode {theme === 'light' ? 'sombre' : 'clair'}
    </button>
  );
}

// App.jsx (extrait)
function App() {
  return (
    <ThemeProvider>
      <ThemedButton />
      <TaskList />
    </ThemeProvider>
  );
}
```
Le Context API évite le props drilling car `ThemedButton` consomme directement le thème sans que les composants intermédiaires n'aient à passer la prop manuellement.

La cause : lorsque `useContext(AuthContext)` est appelé en dehors d'un `AuthProvider`, `useAuth()` retourne `undefined` (valeur par défaut implicite car `createContext()` a été appelé sans argument). Tenter d'accéder à `user.name` sur `undefined` provoque l'erreur.

Correction simple : fournir une valeur par défaut cohérente : `const AuthContext = createContext({ user: null });`

Correction robuste : vérifier dans `useAuth()` que le contexte n'est pas undefined et lever une erreur explicite :
```javascript
export function useAuth() {
  const context = useContext(AuthContext);
  if (context === undefined) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
}
```
Cela rend l'erreur plus claire et évite des bugs silencieux.

La stratégie consiste à <strong>séparer les contextes par domaine fonctionnel et par fréquence de changement</strong> :
- Un contexte pour les données stables ou rarement modifiées (ex: utilisateur connecté, thème)
- Un contexte pour les données qui changent fréquemment (ex: panier)
- Éventuellement un troisième pour les préférences utilisateur

```javascript
// UserContext.jsx (données stables)
const UserContext = createContext();

// CartContext.jsx (données fréquentes)
const CartContext = createContext();

// Dans CartContext, on utilise useReducer pour les actions fréquentes
function CartProvider({ children }) {
  const [state, dispatch] = useReducer(cartReducer, []);
  // seuls les composants qui consomment CartContext re-rendent
  return <CartContext.Provider value={{ state, dispatch }}>{children}</CartContext.Provider>;
}

// App.jsx
function App() {
  return (
    <UserProvider>
      <CartProvider>
        <ThemeProvider>
          <MainApp />
        </ThemeProvider>
      </CartProvider>
    </UserProvider>
  );
}
```
Chaque composant ne consomme que les contextes dont il a besoin. Ainsi, une mise à jour du panier ne re-rend pas les composants qui ne lisent que l'utilisateur ou le thème.

```javascript
// LanguageContext.jsx
import { createContext, useState, useContext } from 'react';

const LanguageContext = createContext();

export function LanguageProvider({ children }) {
  const [language, setLanguage] = useState('fr');
  return (
    <LanguageContext.Provider value={{ language, setLanguage }}>
      {children}
    </LanguageContext.Provider>
  );
}

export function useLanguage() {
  return useContext(LanguageContext);
}

// App.jsx
import { LanguageProvider } from './LanguageContext';
import Header from './Header';
import WelcomeMessage from './WelcomeMessage';

function App() {
  return (
    <LanguageProvider>
      <Header />
      <WelcomeMessage />
    </LanguageProvider>
  );
}

// Header.jsx (plus aucune prop)
import NavBar from './NavBar';

export default function Header() {
  return <NavBar />;
}

// NavBar.jsx (plus aucune prop)
import LanguageSwitcher from './LanguageSwitcher';

export default function NavBar() {
  return <LanguageSwitcher />;
}

// LanguageSwitcher.jsx
import { useLanguage } from './LanguageContext';

export default function LanguageSwitcher() {
  const { language, setLanguage } = useLanguage();
  return (
    <select value={language} onChange={(e) => setLanguage(e.target.value)}>
      <option value="fr">Français</option>
      <option value="en">English</option>
    </select>
  );
}

// WelcomeMessage.jsx
import { useLanguage } from './LanguageContext';

export default function WelcomeMessage() {
  const { language } = useLanguage();
  return <h1>{language === 'fr' ? 'Bonjour' : 'Hello'} !</h1>;
}
```
Le Provider enveloppe toute l'application. `LanguageSwitcher` et `WelcomeMessage` consomment directement le contexte via `useLanguage()`. `Header` et `NavBar` ne font plus que composer des composants sans connaître la langue.

```javascript
export function useNotification() {
  const context = useContext(NotificationContext);
  if (context === undefined) {
    throw new Error('useNotification must be used within a NotificationProvider');
  }
  return context;
}
```
Cette pratique est recommandée pour plusieurs raisons :
1. **Lisibilité** : `useNotification()` est plus clair que `useContext(NotificationContext)`.
2. **Sécurité** : la vérification d'erreur donne un message explicite plutôt qu'un "undefined is not an object" cryptique.
3. **Encapsulation** : si jamais l'implémentation du contexte change (ex: renommage), seul le hook doit être modifié, pas tous les consommateurs.
4. **Réutilisabilité** : on peut ajouter des helpers supplémentaires dans le hook (ex: nettoyage automatique).
